function IGUILayout:ctor(name, parent)
    self.__name = name
    if type(parent) == "table" then
        self.parent = parent.root
    else
        self.parent = parent
    end
    self.root = nil
    self.taskFinished = false
    self:load()
    MemoryPool.pushTable(self)
end

