function IGUILayout:isShowAnim()
    return true
end

function IGUILayout:isLoad()
    return self.root ~= nil
end

function IGUILayout:load()
    if not self:isNeedLoad() then
        return
    end
    if string.find(self.__name, ".json") then
        self.root = GUIManager:loadWindowFromJSON(self.__name, false)
    else
        self.root = GUIManager:getWindowByName(self.__name)
    end
    if not self.root then
        HostApi.log(string.format("Can't find window json [%s]", self.__name), 1)
        return
    end
    if string.find(self.__name, ".json") then
        GUIManager:addLayout(self, self.parent)
    end
    self:onLoad()
end

