end

function IGUILayout:isShow()
    if not self.root then
        return false
    end
    return self.root:IsVisible()
end

function IGUILayout:show(...)
    if ClientHelper.getBoolPrefs("LockUIShowAndHide") and not self:isIgnoreLock() then
        return
    end

    if self:isShow() then
        return
    end
    if not self.root then
        return
    end
    if self:isShowAnim() then
        local color = self.root:GetBackgroundColor()
        if color[4] ~= 0 then
            ---有半透明背景，算弹窗，增加背景子控件弹出动画
            local count = self.root:GetChildCount()
            for index = 1, count do
                local content = self.root:GetChildByIndex(index - 1)
                if content then
                    local scale = 0.5
                    content:SetScale(VectorUtil.newVector3(scale, scale, scale))
                    LuaTimer:scheduleTimer(function()
                        if scale <= 1 then
                            scale = scale + 0.1
                        else
                            scale = scale - 0.025
                        end
                        content:SetScale(VectorUtil.newVector3(scale, scale, scale))
                    end, 20, 10)
                end
            end
            self.root:SetVisible(true)
        else
            self.root:SetVisible(true)
        end
    else
        self.root:SetVisible(true)
    end
    self:onShow(...)
    GuideSystemSetting.onWindowShown(self.__name)
    LogUtil.log("IGUILayout:onShow[" .. self.__name .. "]")
end

function IGUILayout:onShow(...)

end

function IGUILayout:hide()
    if ClientHelper.getBoolPrefs("LockUIShowAndHide") and not self:isIgnoreLock() then
        return
    end

    if self:isAlwaysShow() then
        return
    end
    if self:isShow() then
        self.root:SetVisible(false)
        self:onHide()
    end
    GUILayoutHideEvent:invoke(self.__name)
    LogUtil.log("IGUILayout:onHide[" .. self.__name .. "]")
end

